const jobId = $('Extract Fields').item.json.job_id;
const channelId = $('Extract Fields').item.json.channel_id;
const userId = $('Extract Fields').item.json.user_id;
const audioUrl = ($('Extract Fields').item.json.audio_url || '').trim();
const heygenApiKey = ($env.HEYGEN_API_KEY || '').trim();
const avatarId = String($('Extract Fields').item.json.avatar_id || '').trim();
const useAvatarIvModel = Boolean($('Extract Fields').item.json.use_avatar_iv_model);
const videoWidth = 1080;
const videoHeight = 1920;
const speed = 1.3;
const captionEnabled = false;
const pollIntervalSeconds = Math.max(1, Number($env.HEYGEN_POLL_INTERVAL_SECONDS || 10));
const maxWaitSeconds = Math.max(pollIntervalSeconds, Number($env.HEYGEN_MAX_WAIT_SECONDS || 900));
const mockEnabled = ['1', 'true', 'yes', 'on'].includes(String($env.HEYGEN_MOCK_ENABLED || 'false').trim().toLowerCase());
const mockVideoUrl = String($env.HEYGEN_MOCK_VIDEO_URL || 'https://samplelib.com/lib/preview/mp4/sample-5s.mp4').trim();
const kstDate = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Asia/Seoul',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
}).format(new Date()).replace(/-/g, '');
const videoFilename = `${kstDate}-${jobId}.mp4`;

function describeError(error) {
  const responseBody = error?.response?.body;
  if (responseBody) {
    if (typeof responseBody === 'string') {
      return responseBody;
    }
    try {
      return JSON.stringify(responseBody);
    } catch {
      return String(responseBody);
    }
  }
  return error && error.message ? error.message : String(error);
}

function audioHost(url) {
  try {
    return new URL(url).host;
  } catch {
    return '';
  }
}

function extractCost(payload) {
  if (payload == null) return null;
  if (typeof payload === 'number' && Number.isFinite(payload)) return payload;
  if (Array.isArray(payload)) {
    for (const item of payload) {
      const found = extractCost(item);
      if (found != null) return found;
    }
    return null;
  }
  if (typeof payload !== 'object') return null;
  for (const key of ['cost_usd', 'costUsd', 'credits_cost_usd', 'creditsCostUsd', 'total_cost_usd', 'totalCostUsd', 'billed_cost_usd', 'billedCostUsd']) {
    const found = extractCost(payload[key]);
    if (found != null) return found;
  }
  for (const key of ['cost', 'billing', 'usage', 'data']) {
    const found = extractCost(payload[key]);
    if (found != null) return found;
  }
  return null;
}

const requestSnapshot = {
  avatar_id: avatarId,
  use_avatar_iv_model: useAvatarIvModel,
  voice_type: 'audio',
  has_audio_url: !!audioUrl,
  audio_url_host: audioHost(audioUrl),
  speed,
  dimension: { width: videoWidth, height: videoHeight },
  caption: captionEnabled,
};

function buildFailedMessage(pollError) {
  const code = String(pollError?.code || '').trim();
  const detail = String(pollError?.detail || '').trim();
  const message = String(pollError?.message || '').trim();
  const activity = String(pollError?.activity_name || '').trim();
  const mergedDetail = detail || message;
  const parts = [];
  if (code) parts.push(code);
  if (mergedDetail) parts.push(mergedDetail);
  if (activity) parts.push(`activity=${activity}`);
  return {
    code,
    detail: mergedDetail,
    activity,
    message: parts.join(' | ') || 'failed',
    raw: pollError || {},
  };
}

try {
  if (!audioUrl) {
    throw new Error('audio_url is required');
  }
  if (!avatarId) {
    throw new Error('avatar_id is required from approval step');
  }

  if (mockEnabled) {
    if (!mockVideoUrl) {
      throw new Error('HEYGEN_MOCK_VIDEO_URL is not configured');
    }
    return {
      json: {
        ok: true,
        completed: true,
        status: 'completed',
        video_url: mockVideoUrl,
        video_id: `mock-${jobId}`,
        video_filename: videoFilename,
        avatar_id: avatarId,
        avatar_type: 'mock',
        use_avatar_iv_model: useAvatarIvModel,
        video_width: videoWidth,
        video_height: videoHeight,
        speed,
        caption_enabled: captionEnabled,
        mock_enabled: true,
        request_snapshot: requestSnapshot,
        create_response: {},
        poll_response: {},
        cost_usd: null,
        job_id: jobId,
        channel_id: channelId,
        user_id: userId,
      },
    };
  }

  if (!heygenApiKey) {
    throw new Error('HEYGEN_API_KEY is not configured');
  }

  const avatarDetails = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.heygen.com/v2/avatar/${encodeURIComponent(avatarId)}/details`,
    headers: { 'X-Api-Key': heygenApiKey },
    json: true,
    timeout: 30000,
  });
  const avatarType = avatarDetails.data?.type || avatarDetails.data?.avatar?.type || 'avatar';
  const appliedAvatarIvModel = avatarType === 'talking_photo' && useAvatarIvModel;
  const character = avatarType === 'talking_photo'
    ? {
        type: 'talking_photo',
        talking_photo_id: avatarId,
        ...(appliedAvatarIvModel ? { use_avatar_iv_model: true } : {}),
      }
    : {
        type: 'avatar',
        avatar_id: avatarId,
        avatar_style: 'normal',
      };

  const videoBody = {
    video_inputs: [{
      character,
      voice: {
        type: 'audio',
        audio_url: audioUrl,
        speed,
      },
    }],
    dimension: { width: videoWidth, height: videoHeight },
    caption: captionEnabled,
  };

  const videoData = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.heygen.com/v2/video/generate',
    headers: {
      'X-Api-Key': heygenApiKey,
      'Content-Type': 'application/json',
    },
    body: videoBody,
    json: true,
    timeout: 300000,
  });

  const videoId = videoData.data?.video_id;
  if (!videoId) {
    throw new Error(`HeyGen create video returned no video_id: ${JSON.stringify(videoData)}`);
  }

  const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
  const deadline = Date.now() + (maxWaitSeconds * 1000);
  let videoUrl = '';
  let status = 'processing';
  let failedError = { code: '', detail: '', activity: '', message: '', raw: {} };
  let pollData = {};

  while (Date.now() < deadline) {
    await sleep(pollIntervalSeconds * 1000);
    pollData = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.heygen.com/v1/video_status.get?video_id=${encodeURIComponent(videoId)}`,
      headers: { 'X-Api-Key': heygenApiKey },
      json: true,
      timeout: 30000,
    });

    status = pollData.data?.status || 'processing';
    if (status === 'completed') {
      videoUrl = pollData.data?.video_url || '';
      break;
    }
    if (status === 'failed') {
      failedError = buildFailedMessage(pollData.data?.error);
      break;
    }
  }

  if (status !== 'completed' && status !== 'failed') {
    status = 'timeout';
  }

  return {
    json: {
      ok: status === 'completed' && !!videoUrl,
      completed: status === 'completed' && !!videoUrl,
      status,
      error: status === 'failed' ? failedError.message : '',
      error_code: status === 'failed' ? failedError.code : '',
      error_detail: status === 'failed' ? failedError.detail : '',
      error_activity: status === 'failed' ? failedError.activity : '',
      heygen_error: status === 'failed' ? failedError.raw : {},
      video_url: videoUrl,
      video_id: videoId,
      video_filename: videoFilename,
      avatar_id: avatarId,
      avatar_type: avatarType,
      use_avatar_iv_model: appliedAvatarIvModel,
      video_width: videoWidth,
      video_height: videoHeight,
      speed,
      caption_enabled: captionEnabled,
      mock_enabled: false,
      request_snapshot: requestSnapshot,
      create_response: videoData,
      poll_response: pollData,
      cost_usd: extractCost(pollData) ?? extractCost(videoData),
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
} catch (e) {
  const message = describeError(e);
  return {
    json: {
      ok: false,
      completed: false,
      status: 'failed',
      error: message,
      request_snapshot: requestSnapshot,
      create_response: {},
      poll_response: {},
      video_url: '',
      video_filename: videoFilename,
      avatar_id: avatarId,
      use_avatar_iv_model: useAvatarIvModel,
      job_id: jobId,
      channel_id: channelId,
      user_id: userId,
    },
  };
}
